import logging
import json
import os
from datetime import datetime
import azure.functions as func
from azure.identity import DefaultAzureCredential
from azure.storage.blob import BlobServiceClient
from azure.cosmos import CosmosClient
from azure.eventgrid import EventGridPublisherClient
from azure.core.messaging import CloudEvent

# Configuration
STORAGE_ACCOUNT_URL = os.environ.get("STORAGE_ACCOUNT_URL", "https://<storage-account>.blob.core.windows.net")
COSMOS_ENDPOINT = os.environ.get("COSMOS_ENDPOINT", "https://<cosmos-account>.documents.azure.com:443/")
COSMOS_DATABASE = os.environ.get("COSMOS_DATABASE", "ProcessedFiles")
COSMOS_CONTAINER = os.environ.get("COSMOS_CONTAINER", "FileResults")
EVENT_GRID_ENDPOINT = os.environ.get("EVENT_GRID_ENDPOINT", "https://<topic-name>.<region>.eventgrid.azure.net/api/events")
SOURCE_CONTAINER = os.environ.get("SOURCE_CONTAINER", "input-files")

# Initialize clients with Managed Identity
credential = DefaultAzureCredential()
blob_service_client = BlobServiceClient(account_url=STORAGE_ACCOUNT_URL, credential=credential)
cosmos_client = CosmosClient(url=COSMOS_ENDPOINT, credential=credential)
event_grid_client = EventGridPublisherClient(EVENT_GRID_ENDPOINT, credential)

# Get Cosmos DB database and container
database = cosmos_client.get_database_client(COSMOS_DATABASE)
container = database.get_container_client(COSMOS_CONTAINER)

app = func.FunctionApp()

@app.blob_trigger(arg_name="myblob", path=f"{SOURCE_CONTAINER}/{{name}}", connection="STORAGE_ACCOUNT_URL")
def process_blob(myblob: func.InputStream):
    logging.info(f"Processing blob: {myblob.name}, Size: {myblob.length} bytes")
    
    try:
        # Read and process the blob content
        blob_content = myblob.read()
        content_str = blob_content.decode('utf-8')
        
        # Process the file (example: count lines, words, characters)
        lines = content_str.split('\n')
        words = content_str.split()
        
        processing_result = {
            'id': myblob.name.replace('/', '_').replace('.', '_') + '_' + datetime.utcnow().strftime('%Y%m%d%H%M%S'),
            'file_name': myblob.name,
            'file_size': myblob.length,
            'processed_at': datetime.utcnow().isoformat(),
            'line_count': len(lines),
            'word_count': len(words),
            'character_count': len(content_str),
            'status': 'completed'
        }
        
        # Write results to Cosmos DB
        container.upsert_item(processing_result)
        logging.info(f"Successfully wrote results to Cosmos DB for {myblob.name}")
        
        # Send notification via Event Grid
        event = CloudEvent(
            type="FileProcessing.Completed",
            source=f"/blobstorage/{SOURCE_CONTAINER}",
            data={
                'file_name': myblob.name,
                'file_size': myblob.length,
                'processed_at': processing_result['processed_at'],
                'line_count': processing_result['line_count'],
                'word_count': processing_result['word_count'],
                'cosmos_document_id': processing_result['id']
            }
        )
        
        event_grid_client.send([event])
        logging.info(f"Successfully sent Event Grid notification for {myblob.name}")
        
    except Exception as e:
        logging.error(f"Error processing blob {myblob.name}: {str(e)}")
        
        # Write error to Cosmos DB
        error_result = {
            'id': myblob.name.replace('/', '_').replace('.', '_') + '_error_' + datetime.utcnow().strftime('%Y%m%d%H%M%S'),
            'file_name': myblob.name,
            'file_size': myblob.length,
            'processed_at': datetime.utcnow().isoformat(),
            'status': 'failed',
            'error_message': str(e)
        }
        
        try:
            container.upsert_item(error_result)
        except Exception as cosmos_error:
            logging.error(f"Failed to write error to Cosmos DB: {str(cosmos_error)}")
        
        # Send error notification via Event Grid
        try:
            error_event = CloudEvent(
                type="FileProcessing.Failed",
                source=f"/blobstorage/{SOURCE_CONTAINER}",
                data={
                    'file_name': myblob.name,
                    'error_message': str(e),
                    'processed_at': error_result['processed_at']
                }
            )
            event_grid_client.send([error_event])
        except Exception as eg_error:
            logging.error(f"Failed to send error event to Event Grid: {str(eg_error)}")
        
        raise

@app.function_name(name="GetProcessingResults")
@app.route(route="results/{file_name}", methods=["GET"])
def get_processing_results(req: func.HttpRequest) -> func.HttpResponse:
    file_name = req.route_params.get('file_name')
    
    try:
        # Query Cosmos DB for results
        query = f"SELECT * FROM c WHERE c.file_name LIKE '%{file_name}%' ORDER BY c.processed_at DESC"
        items = list(container.query_items(query=query, enable_cross_partition_query=True))
        
        return func.HttpResponse(
            json.dumps(items, indent=2),
            mimetype="application/json",
            status_code=200
        )
    except Exception as e:
        logging.error(f"Error querying Cosmos DB: {str(e)}")
        return func.HttpResponse(
            json.dumps({'error': str(e)}),
            mimetype="application/json",
            status_code=500
        )

@app.function_name(name="ListBlobs")
@app.route(route="blobs", methods=["GET"])
def list_blobs(req: func.HttpRequest) -> func.HttpResponse:
    try:
        container_client = blob_service_client.get_container_client(SOURCE_CONTAINER)
        blobs = []
        
        for blob in container_client.list_blobs():
            blobs.append({
                'name': blob.name,
                'size': blob.size,
                'created_on': blob.creation_time.isoformat() if blob.creation_time else None,
                'last_modified': blob.last_modified.isoformat() if blob.last_modified else None
            })
        
        return func.HttpResponse(
            json.dumps(blobs, indent=2),
            mimetype="application/json",
            status_code=200
        )
    except Exception as e:
        logging.error(f"Error listing blobs: {str(e)}")
        return func.HttpResponse(
            json.dumps({'error': str(e)}),
            mimetype="application/json",
            status_code=500
        )

@app.function_name(name="HealthCheck")
@app.route(route="health", methods=["GET"])
def health_check(req: func.HttpRequest) -> func.HttpResponse:
    health_status = {
        'status': 'healthy',
        'timestamp': datetime.utcnow().isoformat(),
        'services': {}
    }
    
    # Check Blob Storage
    try:
        blob_service_client.get_service_properties()
        health_status['services']['blob_storage'] = 'healthy'
    except Exception as e:
        health_status['services']['blob_storage'] = f'unhealthy: {str(e)}'
        health_status['status'] = 'degraded'
    
    # Check Cosmos DB
    try:
        database.read()
        health_status['services']['cosmos_db'] = 'healthy'
    except Exception as e:
        health_status['services']['cosmos_db'] = f'unhealthy: {str(e)}'
        health_status['status'] = 'degraded'
    
    status_code = 200 if health_status['status'] == 'healthy' else 503
    
    return func.HttpResponse(
        json.dumps(health_status, indent=2),
        mimetype="application/json",
        status_code=status_code
    )